CREATE TYPE "Role" AS ENUM ('USER', 'ADMIN');
CREATE TYPE "Rarity" AS ENUM ('CONSUMER_GRADE', 'INDUSTRIAL_GRADE', 'MIL_SPEC', 'RESTRICTED', 'CLASSIFIED', 'COVERT', 'RARE_SPECIAL_ITEM');
CREATE TYPE "ItemWear" AS ENUM ('BATTLE_SCARRED', 'WELL_WORN', 'FIELD_TESTED', 'MINIMAL_WEAR', 'FACTORY_NEW');
CREATE TYPE "HistoryType" AS ENUM ('CASE_OPEN', 'ITEM_SELL', 'UPGRADE_SUCCESS', 'UPGRADE_FAIL', 'CONTRACT', 'BALANCE_TOPUP');
CREATE TABLE "User" ("id" TEXT NOT NULL,"email" TEXT NOT NULL,"username" TEXT NOT NULL,"passwordHash" TEXT NOT NULL,"role" "Role" NOT NULL DEFAULT 'USER',"balance" INTEGER NOT NULL DEFAULT 2500,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "User_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Item" ("id" TEXT NOT NULL,"weapon" TEXT NOT NULL,"skin" TEXT NOT NULL,"rarity" "Rarity" NOT NULL,"price" INTEGER NOT NULL,"imageUrl" TEXT NOT NULL,"wear" "ItemWear" NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "Item_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Case" ("id" TEXT NOT NULL,"name" TEXT NOT NULL,"description" TEXT NOT NULL,"price" INTEGER NOT NULL,"imageUrl" TEXT NOT NULL,"accentColor" TEXT NOT NULL DEFAULT '#f59e0b',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "Case_pkey" PRIMARY KEY ("id"));
CREATE TABLE "CaseItem" ("id" TEXT NOT NULL,"caseId" TEXT NOT NULL,"itemId" TEXT NOT NULL,"chance" DOUBLE PRECISION NOT NULL,CONSTRAINT "CaseItem_pkey" PRIMARY KEY ("id"));
CREATE TABLE "InventoryItem" ("id" TEXT NOT NULL,"userId" TEXT NOT NULL,"itemId" TEXT NOT NULL,"acquiredAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"locked" BOOLEAN NOT NULL DEFAULT false,CONSTRAINT "InventoryItem_pkey" PRIMARY KEY ("id"));
CREATE TABLE "History" ("id" TEXT NOT NULL,"userId" TEXT NOT NULL,"type" "HistoryType" NOT NULL,"title" TEXT NOT NULL,"metadata" JSONB NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "History_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "User_email_key" ON "User"("email");
CREATE UNIQUE INDEX "User_username_key" ON "User"("username");
CREATE INDEX "Item_price_idx" ON "Item"("price");
CREATE INDEX "Item_rarity_idx" ON "Item"("rarity");
CREATE UNIQUE INDEX "Case_name_key" ON "Case"("name");
CREATE UNIQUE INDEX "CaseItem_caseId_itemId_key" ON "CaseItem"("caseId", "itemId");
CREATE INDEX "InventoryItem_userId_idx" ON "InventoryItem"("userId");
CREATE INDEX "History_userId_createdAt_idx" ON "History"("userId", "createdAt");
ALTER TABLE "CaseItem" ADD CONSTRAINT "CaseItem_caseId_fkey" FOREIGN KEY ("caseId") REFERENCES "Case"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "CaseItem" ADD CONSTRAINT "CaseItem_itemId_fkey" FOREIGN KEY ("itemId") REFERENCES "Item"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "InventoryItem" ADD CONSTRAINT "InventoryItem_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "InventoryItem" ADD CONSTRAINT "InventoryItem_itemId_fkey" FOREIGN KEY ("itemId") REFERENCES "Item"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "History" ADD CONSTRAINT "History_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE;
